float dist(Point p1, Point p2, int dim) {
  int i;
  float result = 0.0;
  for (i = 0; i < dim; i++)
    result += (p1.coord[i] - p2.coord[i]) * (p1.coord[i] - p2.coord[i]);
#ifdef INSERT_WASTE
  float s = waste(result);
  result += s;
  result -= s;
#endif
  return (result);
}

float pgain(long x, Points *points, float z, long int *numcenters, int kmax,
            bool *is_center, int *center_table, char *switch_membership,
            double *serial_t, double *, double *, double *, double *) {
  float gl_cost = 0.0f;
#ifdef PROFILE_TMP
  double t_start = gettime();
#endif

  int K = (int)(*numcenters);
  int num = (int)points->num;
  int dim = points->dim;
  (void)kmax;
  (void)dim;

  int count = 0;
  for (int i = 0; i < num; i++) {
    if (is_center[i]) center_table[i] = count++;
  }

  size_t needed_work = (size_t)(K + 1) * (size_t)num;
  if (needed_work > work_mem_cap) {
    float* nw = (float*)realloc(work_mem_h, needed_work * sizeof(float));
    if (!nw) quit((char*)"out of memory in pgain work_mem_h");
    work_mem_h = nw;
    work_mem_cap = needed_work;
  }
  if ((size_t)(K + 1) > gl_lower_cap) {
    float* ng = (float*)realloc(gl_lower, (size_t)(K + 1) * sizeof(float));
    if (!ng) quit((char*)"out of memory in pgain gl_lower");
    gl_lower = ng;
    gl_lower_cap = (size_t)(K + 1);
  }
  if ((size_t)num > p_cap) {
    Point_Struct* np = (Point_Struct*)realloc(p_h, (size_t)num * sizeof(Point_Struct));
    if (!np) quit((char*)"out of memory in pgain p_h");
    p_h = np;
    p_cap = (size_t)num;
  }

  memset(switch_membership, 0, (size_t)num * sizeof(char));
  for (size_t i = 0; i < needed_work; i++) work_mem_h[i] = 0.0f;

#pragma omp parallel for schedule(static)
  for (int thread_id = 0; thread_id < num; thread_id++) {
    float x_cost = 0.0f;
    for (int i = 0; i < points->dim; i++) {
      float d = points->p[thread_id].coord[i] - points->p[x].coord[i];
      x_cost += d * d;
    }
    x_cost *= points->p[thread_id].weight;
    float current_cost = points->p[thread_id].cost;
    int base = thread_id * (K + 1);

    if (x_cost < current_cost) {
      switch_membership[thread_id] = '1';
      work_mem_h[base + K] = x_cost - current_cost;
    } else {
      int assign = (int)points->p[thread_id].assign;
      int addr = base + center_table[assign];
      work_mem_h[addr] += current_cost - x_cost;
    }
  }

  int numclose = 0;
  gl_cost = z;

  for (int i = 0; i < num; i++) {
    if (is_center[i]) {
      float low = z;
      for (int j = 0; j < num; j++) {
        low += work_mem_h[(size_t)j * (K + 1) + center_table[i]];
      }
      gl_lower[center_table[i]] = low;
      if (low > 0) {
        numclose++;
        work_mem_h[(size_t)i * (K + 1) + K] -= low;
      }
    }
    gl_cost += work_mem_h[(size_t)i * (K + 1) + K];
  }

  if (gl_cost < 0) {
#pragma omp parallel for schedule(static)
    for (int i = 0; i < num; i++) {
      bool close_center = gl_lower[center_table[points->p[i].assign]] > 0;
      if ((switch_membership[i] == '1') || close_center) {
        points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
        points->p[i].assign = x;
      }
    }

    for (int i = 0; i < num; i++) {
      if (is_center[i] && gl_lower[center_table[i]] > 0) is_center[i] = false;
    }

    is_center[x] = true;
    *numcenters = *numcenters + 1 - numclose;
  } else {
    gl_cost = 0;
  }

#ifdef PROFILE_TMP
  double t_end = gettime();
  if (serial_t) *serial_t += (t_end - t_start);
#endif
  c++;
  return -gl_cost;
}

float pspeedy(Points *points, float z, long *kcenter, int, pthread_barrier_t*) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  cnt_speedy++;

  for (long k = 0; k < points->num; k++) {
    float distance = dist(points->p[k], points->p[0], points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign = 0;
  }

  *kcenter = 1;
  for (long i = 1; i < points->num; i++) {
    bool to_open = ((float)lrand48() / (float)INT_MAX) < (points->p[i].cost / z);
    if (to_open) {
      (*kcenter)++;
      for (long k = 0; k < points->num; k++) {
        float distance = dist(points->p[i], points->p[k], points->dim);
        if (distance * points->p[k].weight < points->p[k].cost) {
          points->p[k].cost = distance * points->p[k].weight;
          points->p[k].assign = i;
        }
      }
    }
  }

  float totalcost = z * (*kcenter);
  for (long k = 0; k < points->num; k++) totalcost += points->p[k].cost;

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_speedy += t2 - t1;
#endif
  return totalcost;
}

float pFL(Points *points, int *feasible, int numfeasible,
          float z, long *k, int kmax, float cost, long iter, float e,
          int pid, pthread_barrier_t* barrier) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  (void)kmax;
  (void)pid;
  (void)barrier;

  long i;
  long x;
  float change;

  change = cost;
  while (change / cost > 1.0 * e) {
    change = 0.0;
    intshuffle(feasible, numfeasible);
    for (i = 0; i < iter; i++) {
      x = i % numfeasible;
      change += pgain(feasible[x], points, z, k, kmax, is_center, center_table, switch_membership,
                      &serial, &cpu_gpu_memcpy, &memcpy_back, &gpu_malloc, &kernel);
    }
    cost -= change;
  }

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_FL += t2 - t1;
#endif
  return cost;
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int, pthread_barrier_t*) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif

  int numfeasible = (int)points->num;
  if (numfeasible > (ITER * kmin * log((float)kmin)))
    numfeasible = (int)(ITER * kmin * log((float)kmin));
  *feasible = (int *)malloc(numfeasible * sizeof(int));

  if (numfeasible == points->num) {
    for (int i = 0; i < numfeasible; i++) (*feasible)[i] = i;
    return numfeasible;
  }

  float* accumweight = (float*)malloc(sizeof(float) * points->num);
  accumweight[0] = points->p[0].weight;
  for (int i = 1; i < points->num; i++) {
    accumweight[i] = accumweight[i - 1] + points->p[i].weight;
  }
  float totalweight = accumweight[points->num - 1];

  for (int i = 0; i < numfeasible; i++) {
    float w = (lrand48() / (float)INT_MAX) * totalweight;
    int l = 0, r = points->num - 1, k;
    if (accumweight[0] > w) {
      (*feasible)[i] = 0;
      continue;
    }
    while (l + 1 < r) {
      k = (l + r) / 2;
      if (accumweight[k] > w) r = k;
      else l = k;
    }
    (*feasible)[i] = r;
  }

  free(accumweight);
#ifdef PROFILE_TMP
  double t2 = gettime();
  time_select_feasible += t2 - t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long* kfinal,
               int pid, pthread_barrier_t* barrier) {
  (void)pid;
  (void)barrier;

  int i;
  float cost;
  float lastcost;
  float hiz, loz, z;

  static long k;
  static int *feasible;
  static int numfeasible;

  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

  float myhiz = 0;
  for (long kk = 0; kk < points->num; kk++) {
    myhiz += dist(points->p[kk], points->p[0], ptDimension) * points->p[kk].weight;
  }
  hiz = myhiz;

  loz = 0.0;
  z = (hiz + loz) / 2.0;

  if (points->num <= kmax) {
    for (long kk = 0; kk < points->num; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    *kfinal = points->num;
    return cost;
  }

  shuffle(points);
  cost = pspeedy(points, z, &k, pid, barrier);
  i = 0;

  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

  while (k < kmin) {
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      i = 0;
    }
    shuffle(points);
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

  numfeasible = selectfeasible_fast(points, &feasible, kmin, pid, barrier);
  for (int ii = 0; ii < points->num; ii++) {
    is_center[points->p[ii].assign] = true;
  }

  while (1) {
    lastcost = cost;
    (void)lastcost;
    cost = pFL(points, feasible, numfeasible, z, &k, kmax, cost,
               (long)(ITER * kmax * log((float)kmax)), 0.1, pid, barrier);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) ||
        ((k <= kmax + 2) && (k >= kmin - 2))) {
      cost = pFL(points, feasible, numfeasible, z, &k, kmax, cost,
                 (long)(ITER * kmax * log((float)kmax)), 0.001, pid, barrier);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999) * hiz))) {
      break;
    }
  }

  free(feasible);
  *kfinal = k;
  return cost;
}

int contcenters(Points *points) {
  long i, ii;
  float relweight;

  for (i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0 - relweight;
        points->p[points->p[i].assign].coord[ii] += points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }
  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset) {
  long i;
  long k;

  bool *is_a_median = (bool *)calloc(points->num, sizeof(bool));

  for (i = 0; i < points->num; i++) {
    is_a_median[points->p[i].assign] = 1;
  }

  k = centers->num;

  for (i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;
  free(is_a_median);
}

